example.programlisting:
...
route {
    if (is_method("INVITE") && !has_totag()) {
        if (!rust_credit_check("$fU")) {
            sl_send_reply(402, "Insufficient Credit");
            exit;
        }
        xlog("L_INFO", "$fU: balance=$var(credit_balance) max=$var(credit_max_duration)s\n");
    }
}
...

...
route {
    if (is_method("BYE")) {
        # Force balance refresh after call ends
        rust_credit_clear("$fU");
    }
}
...
